const pageHtml = "<!DOCTYPE html>\n<html lang=\"pt-BR\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <meta name=\"description\" content=\"Obrigado por se cadastrar na NextPlay! Sua diversão em um só aplicativo.\">\n  <meta name=\"theme-color\" content=\"#0a0a12\">\n  <title>Obrigado | NextPlay</title>\n  <link rel=\"stylesheet\" href=\"styles.css\">\n  <link rel=\"icon\" type=\"image/png\" href=\"assets/logo-nextplay.png\">\n</head>\n<body>\n\n  <!-- Background Effects -->\n  <div class=\"bg-effects\"></div>\n  <div class=\"light-rays\"></div>\n  <div class=\"particles\">\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n    <div class=\"particle\"></div>\n  </div>\n\n  <!-- Main Content -->\n  <main class=\"thank-you-container\" id=\"thank-you-page\">\n\n    <!-- Logo -->\n    <div class=\"logo-wrapper\">\n      <img src=\"assets/logo-nextplay.png\" alt=\"NextPlay Logo\" id=\"logo\">\n    </div>\n\n    <!-- Success Check Icon -->\n    <div class=\"check-icon-wrapper\" id=\"check-icon\">\n      <div class=\"check-circle\">\n        <svg class=\"check-icon\" viewBox=\"0 0 24 24\" aria-hidden=\"true\">\n          <polyline class=\"checkmark\" points=\"6 12 10 16 18 8\"></polyline>\n        </svg>\n      </div>\n    </div>\n\n    <!-- Heading -->\n    <h1 class=\"heading\">Obrigado!</h1>\n\n\n    <!-- Info Card -->\n    <div class=\"info-card\" id=\"info-card\">\n      <p>\n        <span class=\"emoji\">🎬</span>\n        Em breve você terá acesso a todo o conteúdo da <strong>NextPlay</strong> — \n        sua diversão em um só aplicativo.\n      </p>\n      <p>\n        <span class=\"emoji\">📲</span>\n        Fique de olho no seu WhatsApp para receber as instruções de acesso.\n      </p>\n    </div>\n\n\n\n    <!-- Footer -->\n    <p class=\"footer-text\">\n      © 2026 <a href=\"#\">NextPlay</a> — Sua Diversão em um só Aplicativo\n    </p>\n\n  </main>\n\n</body>\n</html>\n";
const pageCss = "/* ===== RESET & BASE ===== */\n@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');\n\n*,\n*::before,\n*::after {\n  margin: 0;\n  padding: 0;\n  box-sizing: border-box;\n}\n\n:root {\n  --bg-primary: #000000;\n  --bg-secondary: #050505;\n  --purple-start: #7c3aed;\n  --purple-mid: #8b5cf6;\n  --blue-start: #3b82f6;\n  --blue-mid: #60a5fa;\n  --cyan-accent: #22d3ee;\n  --text-primary: #f1f5f9;\n  --text-secondary: #94a3b8;\n  --text-muted: #64748b;\n  --glow-purple: rgba(139, 92, 246, 0.25);\n  --glow-blue: rgba(59, 130, 246, 0.2);\n  --gradient-brand: linear-gradient(135deg, var(--blue-start), var(--purple-start), #a855f7);\n  --gradient-bg: #000000;\n}\n\nhtml {\n  font-size: 16px;\n  scroll-behavior: smooth;\n  min-height: 100%;\n}\n\nbody {\n  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;\n  background: var(--gradient-bg);\n  color: var(--text-primary);\n  min-height: 100vh;\n  min-height: 100dvh;\n  width: 100%;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  overflow-x: hidden;\n  overflow-y: auto;\n  position: relative;\n  padding:\n    max(1rem, env(safe-area-inset-top))\n    max(1rem, env(safe-area-inset-right))\n    max(1rem, env(safe-area-inset-bottom))\n    max(1rem, env(safe-area-inset-left));\n}\n\n/* ===== ANIMATED BACKGROUND ===== */\n.bg-effects {\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  z-index: 0;\n  overflow: hidden;\n}\n\n.bg-effects::before {\n  content: '';\n  position: absolute;\n  width: 300px;\n  height: 300px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(139, 92, 246, 0.08) 0%, transparent 70%);\n  top: -100px;\n  left: 50%;\n  transform: translateX(-50%);\n  animation: pulse-glow 8s ease-in-out infinite;\n  filter: blur(100px);\n}\n\n.bg-effects::after {\n  content: '';\n  position: absolute;\n  width: 250px;\n  height: 250px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(59, 130, 246, 0.06) 0%, transparent 70%);\n  bottom: -100px;\n  left: 50%;\n  transform: translateX(-50%);\n  animation: pulse-glow 8s ease-in-out 4s infinite;\n  filter: blur(100px);\n}\n\n/* Light rays effect - hidden for clean black look */\n.light-rays {\n  display: none;\n}\n\n/* Floating particles */\n.particles {\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  z-index: 0;\n}\n\n.particle {\n  position: absolute;\n  width: 2px;\n  height: 2px;\n  border-radius: 50%;\n  background: var(--purple-mid);\n  opacity: 0;\n  animation: float-particle 12s ease-in-out infinite;\n}\n\n.particle:nth-child(1)  { left: 15%; animation-delay: 0s; animation-duration: 14s; }\n.particle:nth-child(2)  { left: 35%; animation-delay: 2s; animation-duration: 16s; background: var(--blue-mid); }\n.particle:nth-child(3)  { left: 55%; animation-delay: 5s; animation-duration: 12s; }\n.particle:nth-child(4)  { left: 75%; animation-delay: 3s; animation-duration: 15s; background: var(--blue-mid); }\n.particle:nth-child(5)  { left: 90%; animation-delay: 7s; animation-duration: 13s; }\n.particle:nth-child(6)  { display: none; }\n.particle:nth-child(7)  { display: none; }\n.particle:nth-child(8)  { display: none; }\n.particle:nth-child(9)  { display: none; }\n.particle:nth-child(10) { display: none; }\n.particle:nth-child(11) { display: none; }\n.particle:nth-child(12) { display: none; }\n\n/* ===== MAIN CONTAINER ===== */\n.thank-you-container {\n  position: relative;\n  z-index: 1;\n  text-align: center;\n  max-width: 560px;\n  width: 100%;\n  padding: clamp(1rem, 3vw, 2rem);\n  animation: fadeInUp 1s ease-out;\n}\n\n/* ===== LOGO ===== */\n.logo-wrapper {\n  margin-bottom: clamp(1.25rem, 4vh, 2.5rem);\n  animation: fadeInUp 1s ease-out 0.2s both;\n}\n\n.logo-wrapper img {\n  width: clamp(150px, 38vw, 200px);\n  max-width: 100%;\n  height: auto;\n  filter: none;\n  transition: filter 0.4s ease;\n}\n\n.logo-wrapper img:hover {\n  filter: none;\n}\n\n/* ===== CHECK ICON ===== */\n.check-icon-wrapper {\n  margin-bottom: clamp(1rem, 3vh, 2rem);\n  animation: fadeInUp 1s ease-out 0.4s both;\n}\n\n.check-circle {\n  width: clamp(76px, 12vw, 100px);\n  height: clamp(76px, 12vw, 100px);\n  border-radius: 50%;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  background: linear-gradient(135deg, rgba(59, 130, 246, 0.15), rgba(139, 92, 246, 0.15));\n  border: 2px solid transparent;\n  background-clip: padding-box;\n  position: relative;\n  animation: check-pulse 3s ease-in-out infinite;\n}\n\n.check-circle::before {\n  content: '';\n  position: absolute;\n  inset: -2px;\n  border-radius: 50%;\n  background: var(--gradient-brand);\n  z-index: -1;\n  opacity: 0.6;\n}\n\n.check-circle::after {\n  content: '';\n  position: absolute;\n  inset: -2px;\n  border-radius: 50%;\n  background: var(--gradient-brand);\n  z-index: -2;\n  filter: blur(15px);\n  opacity: 0.2;\n  animation: check-pulse 4s ease-in-out infinite;\n}\n\n.check-icon {\n  width: 48%;\n  height: 48%;\n  stroke: var(--text-primary);\n  stroke-width: 2.5;\n  fill: none;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n}\n\n.check-icon .checkmark {\n  stroke-dasharray: 50;\n  stroke-dashoffset: 50;\n  animation: draw-check 0.8s ease-out 1s forwards;\n}\n\n/* ===== TYPOGRAPHY ===== */\n.heading {\n  font-size: clamp(1.8rem, 6vw, 2.5rem);\n  font-weight: 800;\n  letter-spacing: -0.02em;\n  line-height: 1.1;\n  margin-bottom: 1rem;\n  background: var(--gradient-brand);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  animation: fadeInUp 1s ease-out 0.6s both;\n}\n\n.subheading {\n  font-size: 1.15rem;\n  font-weight: 400;\n  color: var(--text-secondary);\n  line-height: 1.6;\n  margin-bottom: 2.5rem;\n  animation: fadeInUp 1s ease-out 0.8s both;\n}\n\n.subheading strong {\n  color: var(--text-primary);\n  font-weight: 600;\n}\n\n/* ===== GLASSMORPHISM CARD ===== */\n.info-card {\n  background: rgba(255, 255, 255, 0.02);\n  backdrop-filter: blur(10px);\n  -webkit-backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.05);\n  border-radius: 20px;\n  padding: clamp(1.25rem, 4vw, 2rem);\n  margin-bottom: clamp(1.5rem, 4vh, 2.5rem);\n  position: relative;\n  overflow: hidden;\n  animation: fadeInUp 1s ease-out 1s both;\n  transition: border-color 0.4s ease, box-shadow 0.4s ease;\n}\n\n.info-card:hover {\n  border-color: rgba(139, 92, 246, 0.12);\n  box-shadow: 0 0 20px rgba(139, 92, 246, 0.04);\n}\n\n.info-card::before {\n  content: '';\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  height: 1px;\n  background: linear-gradient(90deg, transparent, rgba(139, 92, 246, 0.2), rgba(59, 130, 246, 0.2), transparent);\n}\n\n.info-card p {\n  color: var(--text-secondary);\n  font-size: 0.95rem;\n  line-height: 1.7;\n  overflow-wrap: anywhere;\n}\n\n.info-card p + p {\n  margin-top: 0.75rem;\n}\n\n.info-card .emoji {\n  font-size: 1.1rem;\n  margin-right: 0.3rem;\n}\n\n/* ===== CTA BUTTON ===== */\n.cta-wrapper {\n  animation: fadeInUp 1s ease-out 1.2s both;\n}\n\n.cta-button {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.5rem;\n  padding: 1rem 2.5rem;\n  font-size: 1rem;\n  font-weight: 600;\n  font-family: 'Inter', sans-serif;\n  color: #fff;\n  background: var(--gradient-brand);\n  border: none;\n  border-radius: 14px;\n  cursor: pointer;\n  text-decoration: none;\n  position: relative;\n  overflow: hidden;\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n  box-shadow: 0 4px 15px rgba(139, 92, 246, 0.2);\n}\n\n.cta-button:hover {\n  transform: translateY(-2px) scale(1.02);\n  box-shadow: 0 6px 25px rgba(139, 92, 246, 0.3);\n}\n\n.cta-button:active {\n  transform: translateY(0) scale(0.98);\n}\n\n.cta-button::before {\n  content: '';\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(135deg, rgba(255,255,255,0.15), transparent 60%);\n  opacity: 0;\n  transition: opacity 0.3s ease;\n}\n\n.cta-button:hover::before {\n  opacity: 1;\n}\n\n.cta-button svg {\n  width: 20px;\n  height: 20px;\n  transition: transform 0.3s ease;\n}\n\n.cta-button:hover svg {\n  transform: translateX(3px);\n}\n\n/* ===== FOOTER ===== */\n.footer-text {\n  margin-top: clamp(1.5rem, 5vh, 3rem);\n  font-size: 0.8rem;\n  color: var(--text-muted);\n  letter-spacing: 0.05em;\n  animation: fadeInUp 1s ease-out 1.4s both;\n}\n\n.footer-text a {\n  color: var(--purple-mid);\n  text-decoration: none;\n  transition: color 0.3s ease;\n}\n\n.footer-text a:hover {\n  color: var(--blue-mid);\n}\n\n/* ===== ANIMATIONS ===== */\n@keyframes fadeInUp {\n  from {\n    opacity: 0;\n    transform: translateY(30px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes pulse-glow {\n  0%, 100% {\n    opacity: 0.3;\n    transform: translateX(-50%) scale(1);\n  }\n  50% {\n    opacity: 0.5;\n    transform: translateX(-50%) scale(1.05);\n  }\n}\n\n@keyframes check-pulse {\n  0%, 100% {\n    box-shadow: 0 0 0 0 rgba(139, 92, 246, 0.2);\n  }\n  50% {\n    box-shadow: 0 0 0 15px rgba(139, 92, 246, 0);\n  }\n}\n\n@keyframes draw-check {\n  to {\n    stroke-dashoffset: 0;\n  }\n}\n\n@keyframes float-particle {\n  0% {\n    opacity: 0;\n    transform: translateY(100vh) scale(0);\n  }\n  10% {\n    opacity: 0.3;\n  }\n  90% {\n    opacity: 0.3;\n  }\n  100% {\n    opacity: 0;\n    transform: translateY(-20vh) scale(1);\n  }\n}\n\n@keyframes rotate-rays {\n  from { transform: translateX(-50%) rotate(0deg); }\n  to { transform: translateX(-50%) rotate(360deg); }\n}\n\n/* ===== RESPONSIVE ===== */\n@media (max-width: 480px) {\n  body {\n    padding-left: max(0.5rem, env(safe-area-inset-left));\n    padding-right: max(0.5rem, env(safe-area-inset-right));\n  }\n\n  .subheading {\n    font-size: 1rem;\n  }\n\n  .info-card {\n    border-radius: 16px;\n  }\n\n  .cta-button {\n    padding: 0.875rem 2rem;\n    font-size: 0.95rem;\n  }\n\n  .footer-text {\n    font-size: 0.72rem;\n    line-height: 1.5;\n  }\n}\n\n/* Telas baixas e celulares em orientação horizontal */\n@media (max-height: 700px) {\n  body {\n    justify-content: flex-start;\n  }\n\n  .thank-you-container {\n    margin-block: auto;\n  }\n\n  .logo-wrapper,\n  .check-icon-wrapper,\n  .heading,\n  .info-card,\n  .footer-text {\n    margin-bottom: 0.75rem;\n  }\n\n  .footer-text {\n    margin-top: 1rem;\n  }\n}\n\n@media (max-height: 500px) and (orientation: landscape) {\n  .thank-you-container {\n    max-width: 760px;\n    padding-block: 0.5rem;\n  }\n\n  .logo-wrapper img {\n    width: 130px;\n  }\n\n  .check-circle {\n    width: 58px;\n    height: 58px;\n  }\n\n  .heading {\n    font-size: 1.6rem;\n  }\n\n  .info-card {\n    padding: 0.875rem 1.25rem;\n  }\n\n  .info-card p {\n    font-size: 0.85rem;\n    line-height: 1.45;\n  }\n}\n\n/* Respeita a preferência do dispositivo por menos movimento */\n@media (prefers-reduced-motion: reduce) {\n  html {\n    scroll-behavior: auto;\n  }\n\n  *,\n  *::before,\n  *::after {\n    animation-duration: 0.01ms !important;\n    animation-iteration-count: 1 !important;\n  }\n}\n";
const logoBase64 = "";

function decodeBase64(value) {
  return Uint8Array.from(atob(value), (character) => character.charCodeAt(0));
}

function createResponse(request, body, contentType, status = 200) {
  const headers = new Headers({
    "content-type": contentType,
    "cache-control": contentType.startsWith("image/")
      ? "public, max-age=604800, immutable"
      : "public, max-age=300",
    "x-content-type-options": "nosniff",
    "referrer-policy": "strict-origin-when-cross-origin",
  });

  return new Response(request.method === "HEAD" ? null : body, { status, headers });
}

export default {
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method !== "GET" && request.method !== "HEAD") {
      return new Response("Método não permitido", {
        status: 405,
        headers: { allow: "GET, HEAD" },
      });
    }

    if (url.pathname === "/" || url.pathname === "/obrigado.html") {
      return createResponse(request, pageHtml, "text/html; charset=utf-8");
    }

    if (url.pathname === "/styles.css") {
      return createResponse(request, pageCss, "text/css; charset=utf-8");
    }

    if (url.pathname === "/assets/logo-nextplay.png") {
      return createResponse(request, decodeBase64(logoBase64), "image/png");
    }

    return createResponse(request, "Página não encontrada", "text/plain; charset=utf-8", 404);
  },
};
